const CACHE_NAME="martin-cache-v1",ASSETS_TO_CACHE=["/","/bundle.js","/styles.css"];self.addEventListener("install",e=>{e.waitUntil(caches.open(CACHE_NAME).then(e=>e.addAll(ASSETS_TO_CACHE)))}),self.addEventListener("fetch",e=>{e.respondWith(caches.match(e.request).then(t=>t||fetch(e.request).then(t=>{if(e.request.url.match(/\.(mp4|webm|mp3|wav)$/i)||e.request.url.includes("dropbox")){const s=t.clone();caches.open(CACHE_NAME).then(t=>{t.put(e.request,s)})}return t})))});